import type { Metadata } from "next";
import { JetBrains_Mono, Source_Serif_4 } from "next/font/google";
import "./globals.css";
import "../styles/typography.css";
import { JsonLd } from "@/components/seo/JsonLd";

const SITE_URL = process.env.SITE_URL ?? "https://personalwebsite-beta-nine.vercel.app";

// Two faces only — mono for technical content + headlines, serif for long-form.
const fontMono = JetBrains_Mono({
  subsets: ["latin"],
  display: "swap",
  variable: "--font-mono",
});

const fontSerif = Source_Serif_4({
  subsets: ["latin"],
  display: "swap",
  variable: "--font-serif",
});

export const metadata: Metadata = {
  metadataBase: new URL(SITE_URL),
  title: { default: "Michael Quintin", template: "%s — Michael Quintin" },
  description: "Operator. Writer. Founder of Hivemind.",
  openGraph: {
    type: "website",
    siteName: "Michael Quintin",
    url: SITE_URL,
  },
  twitter: { card: "summary_large_image" },
};

export default function RootLayout({ children }: Readonly<{ children: React.ReactNode }>) {
  return (
    <html
      lang="en"
      data-theme="dark"
      suppressHydrationWarning
      className={`${fontMono.variable} ${fontSerif.variable}`}
    >
      <head>
        <script
          // restore stored theme before paint
          dangerouslySetInnerHTML={{
            __html: `try{var t=localStorage.getItem('theme');if(t){document.documentElement.setAttribute('data-theme',t);}}catch(e){}`,
          }}
        />
      </head>
      <body>
        <main id="main" role="main">{children}</main>
        <JsonLd data={{
          "@context": "https://schema.org",
          "@type": "WebSite",
          name: "Michael Quintin",
          url: SITE_URL,
        }} />
      </body>
    </html>
  );
}

